/// 중첩 표 (셀 안의 셀) 내부 문단에 텍스트 삽입 (네이티브).
///
/// 경로: section[sec].paragraphs[pp].controls[outer_ctrl]
///       → Table.cells[outer_cell].paragraphs[outer_cell_para]
///         .controls[inner_ctrl]
///       → Table.cells[inner_cell].paragraphs[inner_cell_para]
pub fn insert_text_in_nested_cell_native(
    &mut self,
    section_idx: usize,
    parent_para_idx: usize,
    outer_ctrl_idx: usize,
    outer_cell_idx: usize,
    outer_cell_para_idx: usize,
    inner_ctrl_idx: usize,
    inner_cell_idx: usize,
    inner_cell_para_idx: usize,
    char_offset: usize,
    text: &str,
) -> Result<String, HwpError> {
    if section_idx >= self.document.sections.len() {
        return Err(HwpError::RenderError(format!(
            "구역 인덱스 {} 범위 초과", section_idx
        )));
    }
    let new_chars_count = text.chars().count();

    // 내부 문단까지 내려가서 텍스트 삽입 + 양쪽 표 dirty 마킹.
    {
        let section = &mut self.document.sections[section_idx];
        if parent_para_idx >= section.paragraphs.len() {
            return Err(HwpError::RenderError(format!(
                "부모 문단 인덱스 {} 범위 초과", parent_para_idx
            )));
        }
        let parent_para = &mut section.paragraphs[parent_para_idx];
        if outer_ctrl_idx >= parent_para.controls.len() {
            return Err(HwpError::RenderError(format!(
                "외부 컨트롤 인덱스 {} 범위 초과", outer_ctrl_idx
            )));
        }
        let outer_table = match &mut parent_para.controls[outer_ctrl_idx] {
            Control::Table(t) => t,
            _ => return Err(HwpError::RenderError(
                "외부 컨트롤이 표가 아닙니다".to_string()
            )),
        };
        if outer_cell_idx >= outer_table.cells.len() {
            return Err(HwpError::RenderError(format!(
                "외부 셀 인덱스 {} 범위 초과", outer_cell_idx
            )));
        }
        let outer_cell = &mut outer_table.cells[outer_cell_idx];
        if outer_cell_para_idx >= outer_cell.paragraphs.len() {
            return Err(HwpError::RenderError(format!(
                "외부 셀 문단 인덱스 {} 범위 초과", outer_cell_para_idx
            )));
        }
        let outer_cell_para = &mut outer_cell.paragraphs[outer_cell_para_idx];
        if inner_ctrl_idx >= outer_cell_para.controls.len() {
            return Err(HwpError::RenderError(format!(
                "내부 컨트롤 인덱스 {} 범위 초과", inner_ctrl_idx
            )));
        }
        let inner_table = match &mut outer_cell_para.controls[inner_ctrl_idx] {
            Control::Table(t) => t,
            _ => return Err(HwpError::RenderError(
                "내부 컨트롤이 표가 아닙니다".to_string()
            )),
        };
        if inner_cell_idx >= inner_table.cells.len() {
            return Err(HwpError::RenderError(format!(
                "내부 셀 인덱스 {} 범위 초과", inner_cell_idx
            )));
        }
        let inner_cell = &mut inner_table.cells[inner_cell_idx];
        if inner_cell_para_idx >= inner_cell.paragraphs.len() {
            return Err(HwpError::RenderError(format!(
                "내부 셀 문단 인덱스 {} 범위 초과", inner_cell_para_idx
            )));
        }
        let inner_para = &mut inner_cell.paragraphs[inner_cell_para_idx];
        inner_para.insert_text_at(char_offset, text);
        inner_table.dirty = true;
        outer_table.dirty = true;
    }

    self.document.sections[section_idx].raw_stream = None;
    self.mark_section_dirty(section_idx);
    // 셀 내부 표는 페이지 레이아웃까지 영향 → 안전하게 섹션 리빌드
    self.rebuild_section(section_idx);

    let new_offset = char_offset + new_chars_count;
    self.event_log.push(DocumentEvent::CellTextChanged {
        section: section_idx, para: parent_para_idx, ctrl: outer_ctrl_idx, cell: outer_cell_idx,
    });
    Ok(super::super::helpers::json_ok_with(&format!(
        "\"charOffset\":{}", new_offset
    )))
}

